func solve(nums []int64) []int64 {
	n := len(nums)
	if n == 0 {
		return []int64{}
	}

	answer := make([]int64, n)

	for i := 0; i < n; i++ {
		score := int64(0)
		for j := i + 1; j < n; j++ {
			// Check if parities are different
			// (nums[i] % 2) != (nums[j] % 2)
			// Since nums[i] >= 1, we can use bitwise AND for parity check (odd & 1 == 1, even & 1 == 0)
			is_i_odd := (nums[i] % 2) != 0
			is_j_odd := (nums[j] % 2) != 0

			if is_i_odd != is_j_odd {
				score++
			}
		}
		answer[i] = score
	}

	return answer
}
