// solve calculates the "score" for each element in nums based on the problem description.
// The score for nums[i] is the count of j such that i < j < n and nums[i] and nums[j] have different parities.
func solve(nums []int64) []int64 {
	n := len(nums)
	if n <= 1 {
		return make([]int64, n)
	}

	answer := make([]int64, n)

	for i := 0; i < n; i++ {
		score := int64(0)
		parityI := nums[i] % 2 // 0 for even, 1 for odd

		// Iterate over all j such that i < j < n
		for j := i + 1; j < n; j++ {
			parityJ := nums[j] % 2

			// Check if parities are different (XOR operation works for 0/1)
			if parityI != parityJ {
				score++
			}
		}
		answer[i] = score
	}

	return answer
}
